SELECT c.id, c.title, c.organizer, c.category, c.cover_image, c.entry_end, c.status, c.entry_count, c.created_datetime, CASE WHEN c.entry_end < CURRENT_DATE THEN '마감' WHEN c.entry_end = CURRENT_DATE THEN 'D-Day' ELSE 'D-' || (c.entry_end - CURRENT_DATE) END AS d_day FROM tbl_contest c WHERE c.status != 'DELETED'
AND (c.title ILIKE '%' || #{keyword} || '%' OR c.organizer ILIKE '%' || #{keyword} || '%')
AND c.category = #{category}
AND c.region = #{region}
AND c.status = #{status}
ORDER BY c.created_datetime DESC LIMIT #{size} OFFSET (#{page} - 1) * #{size}

SELECT COUNT(*)
FROM tbl_contest c
WHERE c.status != 'DELETED'

    AND (c.title ILIKE '%' || #{keyword} || '%'
         OR c.organizer ILIKE '%' || #{keyword} || '%')


    AND c.category = #{category}


    AND c.region = #{region}


    AND c.status = #{status}
